 67	export const validateDRPolicyInputs = (state: DRPolicyState): boolean => {
 68	  const {
 69	    policyName,
 70	    replicationType,
 71	    selectedClusters,
 72	    isClusterSelectionValid,
 73	    replicationBackend,
 74	    cluster1S3Details,
 75	    cluster2S3Details,
 76	    useSameS3Connection,
 77	  } = state;
 78	
 79	  const baseValid =
 80	    isFilled(policyName) &&
 81	    !!replicationType &&
 82	    isClusterSelectionValid &&
 83	    selectedClusters.length === MAX_ALLOWED_CLUSTERS;
 84	
 85	  if (!baseValid) return false;
 86	
 87	  if (replicationBackend === BackendType.ThirdParty) {
 88	    const s3Ok =
 89	      areS3DetailsValid(cluster1S3Details) &&
 90	      (useSameS3Connection || areS3DetailsValid(cluster2S3Details));
 91	    return s3Ok;
 92	  }
 93	
 94	  return true;
 95	};
